    input clk,
    input pass_request,
    output [7:0] clock,
    output red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [7:0] cnt;
reg [1:0] state;
reg p_red, p_yellow, p_green;
reg green;
always @(*) begin
    case (state)
        idle: begin
            if (1) begin
            end
        end
        s1_red: begin
            if (cnt == 3) begin
            end
        end
        s2_yellow: begin
            if (cnt == 3) begin
            end
        end
        s3_green: begin
            if (cnt == 3) begin
            end
        end
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 10;
    end else if (pass_request && green) begin
        cnt <= 10;
    end else if (!green && p_green) begin
        cnt <= 60;
    end else if (!yellow && p_yellow) begin
        cnt <= 5;
    end else if (!red && p_red) begin
        cnt <= 10;
    end else begin
        cnt <= cnt - 1;
    end
end
assign clock = cnt;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        {p_red, p_yellow, p_green} <= 3'b0;
    end else begin
        {p_red, p_yellow, p_green} <= {red, yellow, green};
    end
end
endmodule
